/* Tests based on code generated by Claude Sonnet 4.6. */
use super::*;

// opc values for MOVW instructions.
const MOVW_OPC_MOVZ: u32 = 0b10;
const MOVW_OPC_MOVN: u32 = 0b00;

fn movw_opc(insn: u32) -> u32 {
    (insn >> 29) & 0x3
}
// ── Byte-level accessors ──────────────────────────────────────────────────

fn u16_at(mem: &[u8], off: usize) -> u16 {
    u16::from_le_bytes(mem[off..off + 2].try_into().unwrap())
}

fn u32_at(mem: &[u8], off: usize) -> u32 {
    u32::from_le_bytes(mem[off..off + 4].try_into().unwrap())
}

fn u64_at(mem: &[u8], off: usize) -> u64 {
    u64::from_le_bytes(mem[off..off + 8].try_into().unwrap())
}

// ── Instruction-field decoders ────────────────────────────────────────────

/// Sign-extend a `width`-bit unsigned value to i32.
fn sign_ext(raw: u32, width: u32) -> i32 {
    let shift = 32 - width;
    ((raw << shift) as i32) >> shift
}

fn insn_imm14(insn: u32) -> i32 {
    sign_ext((insn >> 5) & 0x3FFF, 14)
}
fn insn_imm19(insn: u32) -> i32 {
    sign_ext((insn >> 5) & 0x0007_FFFF, 19)
}
fn insn_imm26(insn: u32) -> i32 {
    sign_ext(insn & 0x03FF_FFFF, 26)
}

fn insn_imm21_adr(insn: u32) -> i32 {
    let immlo = (insn >> 29) & 0x3;
    let immhi = (insn >> 5) & 0x0007_FFFF;
    sign_ext((immhi << 2) | immlo, 21)
}

fn insn_imm12_add(insn: u32) -> u32 {
    (insn >> 10) & 0xFFF
}
fn insn_mov_w_imm(insn: u32) -> u16 {
    ((insn >> 5) & 0xFFFF) as u16
}

// ── get_bytes_mut error-variant tests ─────────────────────────────────────

#[test]
fn get_bytes_mut_ok() {
    let mut mem = [1u8, 2, 3, 4, 5, 6, 7, 8];
    let arr: &mut [u8; 4] = get_bytes_mut(&mut mem, 2).unwrap();
    assert_eq!(*arr, [3, 4, 5, 6]);
}

#[test]
fn get_bytes_mut_invalid_offset() {
    let mut mem = [0u8; 4];
    assert_eq!(
        get_bytes_mut::<4>(&mut mem, 5),
        Err(Rel64Error::InvalidOffset { offset: 5 })
    );
}

#[test]
fn get_bytes_mut_not_enough_memory() {
    let mut mem = [0u8; 4];
    // offset 2 is valid but only 2 bytes remain — not enough for 4.
    assert_eq!(
        get_bytes_mut::<4>(&mut mem, 2),
        Err(Rel64Error::NotEnoughMemory { offset: 2 })
    );
}

