#[test]
fn abs64_basic() {
    let mut mem = [0u8; 16];
    abs64_reloc(0xDEAD_BEEF_CAFE_1234, &mut mem, 4).unwrap();
    assert_eq!(u64_at(&mem, 4), 0xDEAD_BEEF_CAFE_1234);
}

#[test]
fn abs32_ok() {
    let mut mem = [0u8; 8];
    abs32_reloc(0x0000_ABCD, &mut mem, 2).unwrap();
    assert_eq!(u32_at(&mem, 2), 0x0000_ABCD);
}

#[test]
fn abs32_overflow() {
    let mut mem = [0u8; 8];
    assert!(matches!(
        abs32_reloc(0x1_0000_0000, &mut mem, 0),
        Err(Rel64Error::InvalidValue { .. })
    ));
}

