#[test]
fn mov_w_abs_g0s_positive() {
    let mut mem = MOVZ_X0.to_le_bytes().to_vec();
    mov_w_abs_g0s_reloc(0x1234, &mut mem, 0).unwrap();
    let insn = u32_at(&mem, 0);
    assert_eq!(movw_opc(insn), MOVW_OPC_MOVZ);
    assert_eq!(insn_mov_w_imm(insn), 0x1234);
}

#[test]
fn mov_w_abs_g0s_minus_one() {
    // -1: MOVN X0, #0 encodes ~0 = -1
    let mut mem = MOVZ_X0.to_le_bytes().to_vec();
    mov_w_abs_g0s_reloc(-1i64, &mut mem, 0).unwrap();
    let insn = u32_at(&mem, 0);
    assert_eq!(movw_opc(insn), MOVW_OPC_MOVN);
    assert_eq!(insn_mov_w_imm(insn), 0x0000);
}

#[test]
fn mov_w_abs_g0s_negative_value() {
    // -0x1234: MOVN with imm = ~(-0x1234)[15:0] = 0x1233
    let mut mem = MOVZ_X0.to_le_bytes().to_vec();
    mov_w_abs_g0s_reloc(-0x1234, &mut mem, 0).unwrap();
    let insn = u32_at(&mem, 0);
    assert_eq!(movw_opc(insn), MOVW_OPC_MOVN);
    assert_eq!(insn_mov_w_imm(insn), 0x1233);
}

#[test]
fn mov_w_abs_g1s_negative() {
    // -0x8000_0000: chunk 1 of ~(-0x8000_0000) >> 16 = 0x7FFF
    let mut mem = MOVZ_X0.to_le_bytes().to_vec();
    mov_w_abs_g1s_reloc(-0x8000_0000, &mut mem, 0).unwrap();
    let insn = u32_at(&mem, 0);
    assert_eq!(movw_opc(insn), MOVW_OPC_MOVN);
    assert_eq!(insn_mov_w_imm(insn), 0x7FFF);
}

#[test]
fn mov_w_abs_g0s_overflow() {
    let mut mem = MOVZ_X0.to_le_bytes().to_vec();
    assert!(matches!(
        mov_w_abs_g0s_reloc(0x1_0000, &mut mem, 0),
        Err(Rel64Error::InvalidValue { .. })
    ));
}

// ── Tag dispatch ──────────────────────────────────────────────────────────

#[test]
fn tag_none_is_noop() {
    let mut mem = [0xFFu8; 8];
    Rel64Tag::None.apply(0, 0, &mut mem, 0).unwrap();
    assert!(mem.iter().all(|&b| b == 0xFF));
}

#[test]
fn tag_abs64_roundtrip() {
    let mut mem = [0u8; 8];
    Rel64Tag::Abs64
        .apply(0, 0x1122_3344_5566_7788, &mut mem, 0)
        .unwrap();
    assert_eq!(u64_at(&mem, 0), 0x1122_3344_5566_7788);
}

#[test]
fn tag_jump26_via_apply() {
    let mut mem = 0x1400_0000u32.to_le_bytes().to_vec();
    // base=0, offset=0 → place=0; target=8 → imm26=2
    Rel64Tag::Jump26.apply(0x0, 0x0008, &mut mem, 0).unwrap();
    assert_eq!(insn_imm26(u32_at(&mem, 0)), 2);
}

#[test]
fn tag_adrp_via_apply() {
    let mut mem = [0u8; 4];
    // base=0x1100, offset=0 → place=0x1100 (page 0x1000)
    // target=0x3500 (page 0x3000) → page diff = 2
    Rel64Tag::AdrPrelPgHi21
        .apply(0x1100, 0x3500, &mut mem, 0)
        .unwrap();
    assert_eq!(insn_imm21_adr(u32_at(&mem, 0)), 2);
}
